7	import { KNEX_READ_CONNECTION, KNEX_WRITE_CONNECTION } from '@modules/db/db.constant';
8	import {
9		IJiraInstallationBase,
10		IJiraInstallationCreate,
11		JiraInstallationStatus,
12	} from '@modules/jira/types/jira-installation.interface';
13	
14	import { TABLE_NAME_JIRA_INSTALLATIONS } from '@constants/db.constant';
15	
16	@Injectable()
17	export class JiraInstallationModel {
18		private readonly logger = new Logger(JiraInstallationModel.name);
19		private readonly tableName = TABLE_NAME_JIRA_INSTALLATIONS;
20	
21		constructor(
22			@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
23			@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
24		) {}
25	
26		async create({
27			data,
28		}: {
29			data: IJiraInstallationCreate;
30		}): Promise<IJiraInstallationBase> {
31			try {
32				const _id = randomUUID();
33				const [created] = await this.knexWrite<IJiraInstallationBase>(this.tableName)
34					.insert({
35						_id,
36						...data,
37						status: JiraInstallationStatus.ACTIVE,
38						created_at: this.knexWrite.fn.now(),
39						updated_at: this.knexWrite.fn.now(),
40					})
41					.returning('*');
42	
43				if (!created) throw new Error('Failed to create jira installation');
44	
45				this.logger.debug(`Created jira installation ${_id}`);
46				return created;
47			} catch (error) {
48				this.logger.error(
49					`Failed to create jira installation: ${(error as Error).message}`,
50				);
51				throw error;
52			}
53		}
54	
55		async findAllActive(): Promise<IJiraInstallationBase[]> {
56			try {
57				return await this.knexRead<IJiraInstallationBase>(this.tableName)
58					.where({ status: JiraInstallationStatus.ACTIVE })
59					.select('*');
60			} catch (error) {
61				this.logger.error(
62					`Failed to find active installations: ${(error as Error).message}`,
63				);
64				throw error;
65			}
66		}
67	
68		async findById({ id }: { id: string }): Promise<IJiraInstallationBase | null> {
69			try {
70				const result = await this.knexRead<IJiraInstallationBase>(this.tableName)
71					.where({ _id: id })
72					.first();
73				return result ?? null;
74			} catch (error) {
75				this.logger.error(`Failed to find installation ${id}: ${(error as Error).message}`);
76				throw error;
77			}
78		}
79	
80		async updateTokens({
81			id,
82			accessToken,
83			refreshToken,
84			tokenExpiresAt,
85		}: {
86			id: string;
87			accessToken: string;
88			refreshToken: string;
89			tokenExpiresAt: Date;
90		}): Promise<void> {
91			try {
92				await this.knexWrite<IJiraInstallationBase>(this.tableName)
93					.where({ _id: id })
94					.update({
95						access_token: accessToken,
96						refresh_token: refreshToken,
97						token_expires_at: tokenExpiresAt,
98						updated_at: this.knexWrite.fn.now(),
99					});
100			} catch (error) {
101				this.logger.error(`Failed to update tokens for ${id}: ${(error as Error).message}`);
102				throw error;
103			}
104		}
105	
106		async markNeedsReauth({ id }: { id: string }): Promise<void> {
107			try {
108				await this.knexWrite<IJiraInstallationBase>(this.tableName)
109					.where({ _id: id })
110					.update({
111						status: JiraInstallationStatus.NEEDS_REAUTH,
112						updated_at: this.knexWrite.fn.now(),
113					});
114			} catch (error) {
115				this.logger.error(
116					`Failed to mark needs_reauth for ${id}: ${(error as Error).message}`,
117				);
118				throw error;
119			}
120		}
121	
122		async markUninstalled({
123			id,
124			companyId,
125		}: {
126			id: string;
127			companyId: string;
128		}): Promise<void> {
129			try {
130				await this.knexWrite<IJiraInstallationBase>(this.tableName)
131					.where({ _id: id, company_id: companyId })
132					.update({
133						status: JiraInstallationStatus.UNINSTALLED,
134						updated_at: this.knexWrite.fn.now(),
135					});
136				this.logger.debug(`Marked jira installation ${id} as uninstalled`);
137			} catch (error) {
138				this.logger.error(
139					`Failed to mark uninstalled for ${id}: ${(error as Error).message}`,
140				);
141				throw error;
142			}
143		}
144	}
