13	@Injectable()
14	export class JiraProjectModel {
15		private readonly logger = new Logger(JiraProjectModel.name);
16		private readonly tableName = TABLE_NAME_JIRA_PROJECTS;
17	
18		constructor(
19			@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
20			@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
21		) {}
22	
23		async upsertMany({
24			installationId,
25			projects,
26		}: {
27			installationId: string;
28			projects: IJiraApiProject[];
29		}): Promise<void> {
30			if (projects.length === 0) return;
31	
32			try {
33				const rows = projects.map((p) => ({
34					_id: randomUUID(),
35					installation_id: installationId,
36					project_key: p.key,
37					project_id: p.id,
38					name: p.name,
39					project_type: p.projectTypeKey,
40					created_at: this.knexWrite.fn.now(),
41					updated_at: this.knexWrite.fn.now(),
42				}));
43	
44				await this.knexWrite<IJiraProjectBase>(this.tableName)
45					.insert(rows)
46					.onConflict(['installation_id', 'project_id'])
47					.merge(['project_key', 'name', 'project_type', 'updated_at']);
48	
49				this.logger.debug(
50					`Upserted ${projects.length} projects for installation ${installationId}`,
51				);
52			} catch (error) {
53				this.logger.error(`Failed to upsert projects: ${(error as Error).message}`);
54				throw error;
55			}
56		}
57	
58		async findByInstallationId({
59			installationId,
60		}: {
61			installationId: string;
62		}): Promise<IJiraProjectBase[]> {
63			try {
64				return await this.knexRead<IJiraProjectBase>(this.tableName)
65					.where({ installation_id: installationId })
66					.select('*');
67			} catch (error) {
68				this.logger.error(
69					`Failed to find projects for installation ${installationId}: ${(error as Error).message}`,
70				);
71				throw error;
72			}
73		}
74	
75		async updateLastSyncedAt({ id }: { id: string }): Promise<void> {
76			try {
77				await this.knexWrite<IJiraProjectBase>(this.tableName).where({ _id: id }).update({
78					last_synced_at: this.knexWrite.fn.now(),
79					updated_at: this.knexWrite.fn.now(),
80				});
81			} catch (error) {
82				this.logger.error(
83					`Failed to update last_synced_at for project ${id}: ${(error as Error).message}`,
84				);
85				throw error;
86			}
87		}
88	
89		async deleteByProjectId({
90			installationId,
91			projectId,
92		}: {
93			installationId: string;
94			projectId: string;
95		}): Promise<void> {
96			try {
97				await this.knexWrite<IJiraProjectBase>(this.tableName)
98					.where({ installation_id: installationId, project_id: projectId })
99					.delete();
100			} catch (error) {
101				this.logger.error(
102					`Failed to delete project ${projectId}: ${(error as Error).message}`,
103				);
104				throw error;
105			}
106		}
107	}
